package com.example.dataproc;

import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.stub.StreamObserver;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Iterator;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;

public class DataTransferClient {
    private final ManagedChannel channel;
    private final DataTransferServiceGrpc.DataTransferServiceBlockingStub blockingStub;
    private final DataTransferServiceGrpc.DataTransferServiceStub asyncStub;

    public DataTransferClient(String host, int port) {
        this.channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .maxInboundMessageSize(Integer.MAX_VALUE)
                .build();
        this.blockingStub = DataTransferServiceGrpc.newBlockingStub(channel)
                .withMaxOutboundMessageSize(Integer.MAX_VALUE);
        this.asyncStub = DataTransferServiceGrpc.newStub(channel)
                .withMaxOutboundMessageSize(Integer.MAX_VALUE);
    }

    public UploadSummary uploadFile(Path file, int chunkSize) throws Exception {
        CountDownLatch latch = new CountDownLatch(1);
        UploadSummary[] result = new UploadSummary[1];
        Throwable[] error = new Throwable[1];

        StreamObserver<UploadSummary> responseObserver = new StreamObserver<>() {
            @Override
            public void onNext(UploadSummary value) {
                result[0] = value;
            }

            @Override
            public void onError(Throwable t) {
                error[0] = t;
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                latch.countDown();
            }
        };

        StreamObserver<UploadChunk> requestObserver = asyncStub.upload(responseObserver);
        byte[] all = Files.readAllBytes(file);
        String uploadId = java.util.UUID.randomUUID().toString();
        int offset = 0;
        while (offset < all.length) {
            int len = Math.min(chunkSize, all.length - offset);
            boolean eof = offset + len >= all.length;
            requestObserver.onNext(UploadChunk.newBuilder()
                    .setUploadId(uploadId)
                    .setFileName(file.getFileName().toString())
                    .setData(com.google.protobuf.ByteString.copyFrom(all, offset, len))
                    .setOffset(offset)
                    .setEof(eof)
                    .build());
            offset += len;
        }
        requestObserver.onCompleted();

        if (!latch.await(5, TimeUnit.MINUTES)) {
            throw new RuntimeException("Upload timed out");
        }
        if (error[0] != null) {
            throw new RuntimeException(error[0]);
        }
        return result[0];
    }

    public void downloadFile(String fileName, Path target, int chunkSize) throws Exception {
        Iterator<DownloadChunk> iterator = blockingStub.download(DownloadRequest.newBuilder()
                .setFileName(fileName)
                .setChunkSize(chunkSize)
                .build());

        try (var out = Files.newOutputStream(target)) {
            while (iterator.hasNext()) {
                DownloadChunk chunk = iterator.next();
                if (!chunk.getEof() && !chunk.getData().isEmpty()) {
                    chunk.getData().writeTo(out);
                }
            }
        }
    }

    public void syncExample() throws Exception {
        CountDownLatch latch = new CountDownLatch(1);
        StreamObserver<TransferMessage> responseObserver = new StreamObserver<>() {
            @Override
            public void onNext(TransferMessage value) {
                System.out.println("SYNC RESPONSE: " + value);
            }

            @Override
            public void onError(Throwable t) {
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                latch.countDown();
            }
        };

        StreamObserver<TransferMessage> requestObserver = asyncStub.sync(responseObserver);

        requestObserver.onNext(TransferMessage.newBuilder()
                .setCorrelationId("ctrl-1")
                .setControl(Control.newBuilder()
                        .setCommand("PING")
                        .putMetadata("source", "client")
                        .build())
                .build());

        requestObserver.onNext(TransferMessage.newBuilder()
                .setCorrelationId("dl-1")
                .setDownloadRequest(DownloadRequest.newBuilder()
                        .setFileName("example.bin")
                        .setChunkSize(1024)
                        .build())
                .build());

        requestObserver.onCompleted();
        latch.await(1, TimeUnit.MINUTES);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(30, TimeUnit.SECONDS);
    }
}